import React, { useState, useEffect } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ onSelectUserStory, onClose, isSidebarVisible, jiraData }) {
  const [loading] = useState(false);  // State to manage loading status
  const [error, setError] = useState(null);  // State to handle errors if they occur

  // If needed, you can update loading/error state based on changes in jiraData
  useEffect(() => {
    if (jiraData.length === 0) {
      setError('No Jira stories available.');
    } else {
      setError(null);
    }
  }, [jiraData]);

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}>
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title"><strong>Imported Jira User Stories</strong></div>

      {loading && <div>Loading...</div>}  {/* Display loading indicator */}
      {error && <div className="error">{error}</div>}  {/* Display error if exists */}

      <div className="jira-stories">
        {/* If no Jira data is available and no loading, show a message */}
        {jiraData && jiraData.length === 0 && !loading ? (
          <div>No Jira stories found.</div>
        ) : (
          jiraData?.map((story, index) => (
            <div
              key={index}  // Use index as key, but ideally it would be better to use a unique identifier (e.g., story.id or story.key)
              className="jira-story-box"
              onClick={() => onSelectUserStory(story)}  // Select the user story when clicked
            >
              <strong>{story.summary}</strong>  {/* Display story summary */}
              <div><b>Assignee:</b> {story.reporter}</div>  {/* Display reporter */}
              <div><b>Description:</b> {story.description}</div>  {/* Display description */}
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
